import React, { useEffect, useState } from 'react';
import axios from 'axios';
import BlogCard from '../components/BlogCard';

const HomePage = () => {
  const [blogs, setBlogs] = useState([]);
  const [filteredBlogs, setFilteredBlogs] = useState([]);
  const [categories, setCategories] = useState([]);
  const [selectedCategory, setSelectedCategory] = useState('All');
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [searchTerm, setSearchTerm] = useState('');

  const API_BASE_URL = process.env.REACT_APP_API_BASE_URL;

  useEffect(() => {
    const fetchBlogsAndCategories = async () => {
      try {
        const blogRes = await axios.get(`${API_BASE_URL}/blogs`);
        const categoryRes = await axios.get(`${API_BASE_URL}/categories`);
        setBlogs(blogRes.data);
        setCategories(categoryRes.data);
        setFilteredBlogs(blogRes.data);
        setLoading(false);
      } catch (err) {
        setError('Failed to load data.');
        setLoading(false);
      }
    };

    fetchBlogsAndCategories();
  }, [API_BASE_URL]);

  const handleCategoryChange = (categoryName) => {
    setSelectedCategory(categoryName);
    filterBlogs(searchTerm, categoryName);
  };

  const handleSearch = (e) => {
    const value = e.target.value;
    setSearchTerm(value);
    filterBlogs(value, selectedCategory);
  };

  const filterBlogs = (search, category) => {
    let results = blogs;

    if (category !== 'All') {
      results = results.filter((blog) => blog.category_name === category);
    }

    if (search.trim() !== '') {
      results = results.filter((blog) =>
        blog.title.toLowerCase().includes(search.toLowerCase())
      );
    }

    setFilteredBlogs(results);
  };

  const handleDelete = async (id) => {
    const confirmDelete = window.confirm("Are you sure you want to delete this blog?");
    if (!confirmDelete) return;

    try {
      await axios.delete(`${API_BASE_URL}/blogs/${id}`);
      const updatedBlogs = blogs.filter((blog) => blog.id !== id);
      setBlogs(updatedBlogs);
      filterBlogs(searchTerm, selectedCategory);
    } catch (err) {
      console.error("Error deleting blog:", err);
    }
  };

  const isAdmin = localStorage.getItem('role') === 'admin';

  if (loading) return <p className="text-center text-gray-500">Loading...</p>;
  if (error) return <p className="text-center text-red-500">{error}</p>;

  return (
    <div className="container mx-auto p-4 grid grid-cols-1 lg:grid-cols-12 gap-8">

      {/* LEFT SIDE - BLOG LIST */}
      <div className="lg:col-span-9">
        {/* Category buttons */}
        <div className="mb-6 flex flex-wrap gap-3 justify-center">
          <button
            onClick={() => handleCategoryChange('All')}
            className={`px-4 py-2 rounded-full ${selectedCategory === 'All' ? 'bg-blue-600 text-white' : 'bg-gray-200 text-gray-700'}`}
          >
            All
          </button>
          {categories.map((category) => (
            <button
              key={category.id}
              onClick={() => handleCategoryChange(category.name)}
              className={`px-4 py-2 rounded-full ${selectedCategory === category.name ? 'bg-blue-600 text-white' : 'bg-gray-200 text-gray-700'}`}
            >
              {category.name}
            </button>
          ))}
        </div>

        {/* Blog Cards */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          {filteredBlogs
            .filter(blog => blog && typeof blog === 'object' && blog.id)
            .map((blog) => (
              <BlogCard key={blog.id} blog={blog} onDelete={handleDelete} isAdmin={isAdmin} />
            ))}
        </div>
      </div>

      {/* RIGHT SIDE - SIDEBAR */}
      <div className="lg:col-span-3 space-y-8">
        {/* Search Bar */}
        <div className="border rounded-lg p-4 shadow-sm">
          <input
            type="text"
            placeholder="Enter your keywords..."
            value={searchTerm}
            onChange={handleSearch}
            className="w-full p-2 border rounded focus:outline-none"
          />
        </div>

        {/* About Me */}
        <div className="border rounded-lg p-4 shadow-sm text-center">
          <h2 className="text-lg font-semibold mb-3 border-b pb-2">About Us</h2>
          <img
            src="https://via.placeholder.com/150"
            alt="Author"
            className="w-28 h-28 rounded-full mx-auto mb-3 object-cover"
          />
          <p className="text-gray-600 text-sm mb-3">
            Lorem Ipsum is simply dummy text of the printing and typesetting industry. 
            Lorem Ipsum has been the industry's standard dummy text.
          </p>
          <button className="bg-black text-white px-4 py-2 rounded">
            About Author
          </button>
        </div>
        {/* Quote Box */}
  <div className="bg-pink-600 text-white p-6 rounded-lg shadow text-center">
    <p className="italic text-lg mb-4">
      "The future belongs to those who believe in the beauty of their dreams."
    </p>
    <button className="bg-white text-pink-600 px-4 py-2 rounded font-semibold">
      Explore Portfolio
    </button>
  </div>

  {/* Popular Posts */}
  <div className="border rounded-lg p-4 shadow-sm">
    <h2 className="text-lg font-semibold mb-3 border-b pb-2">Popular Post</h2>
    <div className="space-y-4">
      <div className="flex items-center space-x-3">
        <img src="https://via.placeholder.com/60" alt="post" className="w-14 h-14 object-cover rounded" />
        <div>
          <p className="text-sm font-medium">Traveling abroad will change you forever</p>
          <p className="text-xs text-gray-500">April 30, 2016</p>
        </div>
      </div>
      <div className="flex items-center space-x-3">
        <img src="https://via.placeholder.com/60" alt="post" className="w-14 h-14 object-cover rounded" />
        <div>
          <p className="text-sm font-medium">Having a new perspective on New York City</p>
          <p className="text-xs text-gray-500">March 10, 2016</p>
        </div>
      </div>
      <div className="flex items-center space-x-3">
        <img src="https://via.placeholder.com/60" alt="post" className="w-14 h-14 object-cover rounded" />
        <div>
          <p className="text-sm font-medium">The incredible talents of street performers</p>
          <p className="text-xs text-gray-500">March 05, 2016</p>
        </div>
      </div>
    </div>
  </div>
</div>
      </div>
  );
};


export default HomePage;
